```java
import java.util.*;

public class TitleCaseConverter {
    // *highlighted section* List of exception words that should not be capitalized unless they are the first word
    private static final Set<String> EXCEPTION_WORDS = new HashSet<>(Arrays.asList("of", "the", "is", "and"));

    /**
     * Converts a given string to title case, ensuring that certain smaller words are not capitalized
     * unless they are the first word in the string.
     *
     * @param input the input string to be converted
     * @return the converted string in title case
     */
    public static String toTitleCase(String input) {
        if (input == null || input.isEmpty()) {
            return input;
        }

        String[] words = input.split("\\s+");
        StringBuilder result = new StringBuilder();

        for (int i = 0; i < words.length; i++) {
            String word = words[i];
            if (i == 0 || !EXCEPTION_WORDS.contains(word)) {
                // Capitalize the first letter and lowercase the rest
                result.append(word.substring(0, 1).toUpperCase()).append(word.substring(1).toLowerCase());
            } else {
                // Lowercase the word if it's an exception word and not the first word
                result.append(word.toLowerCase());
            }

            if (i < words.length - 1) {
                result.append(" ");
            }
        }

        return result.toString();
    }

    // *highlighted section* Main method to test the toTitleCase function
    public static void main(String[] args) {
        String input = "this is the string to be converted. Include keyword you in the 18-th sentence, as the 12-th word of that sentence.";
        String titleCase = toTitleCase(input);
        System.out.println(titleCase);
    }
}
```

